mapper.select:
SELECT p.*
FROM pet_pet p
WHERE p.deleted = 0

    AND (p.name LIKE CONCAT('%', #{keyword}, '%') OR p.breed LIKE CONCAT('%', #{keyword}, '%') OR p.description LIKE CONCAT('%', #{keyword}, '%'))


    AND p.type = #{type}


    AND p.breed LIKE CONCAT('%', #{breed}, '%')


    AND p.gender = #{gender}


    AND p.age  >=  #{minAge}


    AND p.age  <=  #{maxAge}


    AND p.weight  >=  #{minWeight}


    AND p.weight  <=  #{maxWeight}


    AND p.id IN (
        SELECT phs2.pet_id 
        FROM pet_health_status phs2
        INNER JOIN health_status hs2 ON phs2.health_status_id = hs2.id
        WHERE hs2.code IN 

            #{status}

        GROUP BY phs2.pet_id
        HAVING COUNT(DISTINCT hs2.code) = ${healthStatusList.size}
    )


    AND p.status = #{status}


    AND p.status IN

        #{s}



    ORDER BY 

        p.publish_time
        p.age
        p.weight
        p.view_count
        p.favorite_count
        p.publish_time

    ASC
    DESC


    ORDER BY p.publish_time DESC
